tinymce.Resource.add("tinymce.html-i18n.help-keynav.el",`<h1>\u0388\u03BD\u03B1\u03C1\u03BE\u03B7 \u03C0\u03BB\u03BF\u03AE\u03B3\u03B7\u03C3\u03B7\u03C2 \u03BC\u03AD\u03C3\u03C9 \u03C0\u03BB\u03B7\u03BA\u03C4\u03C1\u03BF\u03BB\u03BF\u03B3\u03AF\u03BF\u03C5</h1>

<dl>
  <dt>\u0395\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03C3\u03C4\u03B7 \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE \u03BC\u03B5\u03BD\u03BF\u03CD</dt>
  <dd>Windows \u03AE Linux: Alt+F9</dd>
  <dd>macOS: &#x2325;F9</dd>
  <dt>\u0395\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03C3\u03C4\u03B7 \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE \u03B5\u03C1\u03B3\u03B1\u03BB\u03B5\u03AF\u03C9\u03BD</dt>
  <dd>Windows \u03AE Linux: Alt+F10</dd>
  <dd>macOS: &#x2325;F10</dd>
  <dt>\u0395\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03C3\u03C4\u03BF \u03C5\u03C0\u03BF\u03C3\u03AD\u03BB\u03B9\u03B4\u03BF</dt>
  <dd>Windows \u03AE Linux: Alt+F11</dd>
  <dd>macOS: &#x2325;F11</dd>
  <dt>\u0395\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03C3\u03C4\u03B7\u03BD \u03B5\u03B9\u03B4\u03BF\u03C0\u03BF\u03AF\u03B7\u03C3\u03B7</dt>
  <dd>Windows \u03AE Linux: Alt+F12</dd>
  <dd>macOS: &#x2325;F12</dd>
  <dt>\u0395\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03C3\u03B5 \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE \u03B5\u03C1\u03B3\u03B1\u03BB\u03B5\u03AF\u03C9\u03BD \u03B2\u03AC\u03C3\u03B5\u03B9 \u03C0\u03B5\u03C1\u03B9\u03B5\u03C7\u03BF\u03BC\u03AD\u03BD\u03BF\u03C5</dt>
  <dd>Windows, Linux \u03AE macOS: Ctrl+F9</dd>
</dl>

<p>\u0397 \u03C0\u03BB\u03BF\u03AE\u03B3\u03B7\u03C3\u03B7 \u03B8\u03B1 \u03BE\u03B5\u03BA\u03B9\u03BD\u03AE\u03C3\u03B5\u03B9 \u03B1\u03C0\u03CC \u03C4\u03BF \u03C0\u03C1\u03CE\u03C4\u03BF \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03BF \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7, \u03C0\u03BF\u03C5 \u03B8\u03B1 \u03B5\u03C0\u03B9\u03C3\u03B7\u03BC\u03B1\u03AF\u03BD\u03B5\u03C4\u03B1\u03B9 \u03AE \u03B8\u03B1 \u03B5\u03AF\u03BD\u03B1\u03B9 \u03C5\u03C0\u03BF\u03B3\u03C1\u03B1\u03BC\u03BC\u03B9\u03C3\u03BC\u03AD\u03BD\u03BF,
  \u03CC\u03C0\u03C9\u03C2 \u03C3\u03C4\u03B7\u03BD \u03C0\u03B5\u03C1\u03AF\u03C0\u03C4\u03C9\u03C3\u03B7 \u03C4\u03B7\u03C2 \u03B4\u03B9\u03B1\u03B4\u03C1\u03BF\u03BC\u03AE\u03C2 \u03C4\u03BF\u03C5 \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03BF\u03C5 \u03A5\u03C0\u03BF\u03C3\u03AD\u03BB\u03B9\u03B4\u03BF\u03C5.</p>

<h1>\u03A0\u03BB\u03BF\u03AE\u03B3\u03B7\u03C3\u03B7 \u03BC\u03B5\u03C4\u03B1\u03BE\u03CD \u03B5\u03BD\u03BF\u03C4\u03AE\u03C4\u03C9\u03BD \u03C4\u03BF\u03C5 \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7</h1>

<p>\u0393\u03B9\u03B1 \u03BD\u03B1 \u03BC\u03B5\u03C4\u03B1\u03BA\u03B9\u03BD\u03B7\u03B8\u03B5\u03AF\u03C4\u03B5 \u03B1\u03C0\u03CC \u03BC\u03B9\u03B1 \u03B5\u03BD\u03CC\u03C4\u03B7\u03C4\u03B1 \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7 \u03C3\u03C4\u03B7\u03BD \u03B5\u03C0\u03CC\u03BC\u03B5\u03BD\u03B7, \u03C0\u03B9\u03AD\u03C3\u03C4\u03B5 \u03C4\u03BF \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03BF <strong>Tab</strong>.</p>

<p>\u0393\u03B9\u03B1 \u03BD\u03B1 \u03BC\u03B5\u03C4\u03B1\u03BA\u03B9\u03BD\u03B7\u03B8\u03B5\u03AF\u03C4\u03B5 \u03B1\u03C0\u03CC \u03BC\u03B9\u03B1 \u03B5\u03BD\u03CC\u03C4\u03B7\u03C4\u03B1 \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7 \u03C3\u03C4\u03B7\u03BD \u03C0\u03C1\u03BF\u03B7\u03B3\u03BF\u03CD\u03BC\u03B5\u03BD\u03B7, \u03C0\u03B9\u03AD\u03C3\u03C4\u03B5 \u03C4\u03B1 \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03B1 <strong>Shift+Tab</strong>.</p>

<p>\u0397 \u03C3\u03B5\u03B9\u03C1\u03AC <strong>Tab</strong> \u03B1\u03C5\u03C4\u03CE\u03BD \u03C4\u03C9\u03BD \u03B5\u03BD\u03BF\u03C4\u03AE\u03C4\u03C9\u03BD \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7 \u03B5\u03AF\u03BD\u03B1\u03B9 \u03B7 \u03B5\u03BE\u03AE\u03C2:</p>

<ol>
  <li>\u0393\u03C1\u03B1\u03BC\u03BC\u03AE \u03BC\u03B5\u03BD\u03BF\u03CD</li>
  <li>\u039A\u03AC\u03B8\u03B5 \u03BF\u03BC\u03AC\u03B4\u03B1 \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE\u03C2 \u03B5\u03C1\u03B3\u03B1\u03BB\u03B5\u03AF\u03C9\u03BD</li>
  <li>\u03A0\u03BB\u03B1\u03CA\u03BD\u03AE \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE</li>
  <li>\u0394\u03B9\u03B1\u03B4\u03C1\u03BF\u03BC\u03AE \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03BF\u03C5 \u03C3\u03C4\u03BF \u03C5\u03C0\u03BF\u03C3\u03AD\u03BB\u03B9\u03B4\u03BF</li>
  <li>\u039A\u03BF\u03C5\u03BC\u03C0\u03AF \u03B5\u03BD\u03B1\u03BB\u03BB\u03B1\u03B3\u03AE\u03C2 \u03BC\u03AD\u03C4\u03C1\u03B7\u03C3\u03B7\u03C2 \u03BB\u03AD\u03BE\u03B5\u03C9\u03BD \u03C3\u03C4\u03BF \u03C5\u03C0\u03BF\u03C3\u03AD\u03BB\u03B9\u03B4\u03BF</li>
  <li>\u03A3\u03CD\u03BD\u03B4\u03B5\u03C3\u03BC\u03BF\u03C2 \u03B5\u03C0\u03C9\u03BD\u03C5\u03BC\u03AF\u03B1\u03C2 \u03C3\u03C4\u03BF \u03C5\u03C0\u03BF\u03C3\u03AD\u03BB\u03B9\u03B4\u03BF</li>
  <li>\u039B\u03B1\u03B2\u03AE \u03B1\u03BB\u03BB\u03B1\u03B3\u03AE\u03C2 \u03BC\u03B5\u03B3\u03AD\u03B8\u03BF\u03C5\u03C2 \u03C0\u03C1\u03BF\u03B3\u03C1\u03AC\u03BC\u03BC\u03B1\u03C4\u03BF\u03C2 \u03B5\u03C0\u03B5\u03BE\u03B5\u03C1\u03B3\u03B1\u03C3\u03AF\u03B1\u03C2 \u03C3\u03C4\u03BF \u03C5\u03C0\u03BF\u03C3\u03AD\u03BB\u03B9\u03B4\u03BF</li>
</ol>

<p>\u0395\u03AC\u03BD \u03B4\u03B5\u03BD \u03B5\u03BC\u03C6\u03B1\u03BD\u03AF\u03B6\u03B5\u03C4\u03B1\u03B9 \u03B5\u03BD\u03CC\u03C4\u03B7\u03C4\u03B1 \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7, \u03C0\u03B1\u03C1\u03B1\u03BB\u03B5\u03AF\u03C0\u03B5\u03C4\u03B1\u03B9.</p>

<p>\u0395\u03AC\u03BD \u03B7 \u03B5\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03C0\u03BB\u03BF\u03AE\u03B3\u03B7\u03C3\u03B7\u03C2 \u03B2\u03C1\u03AF\u03C3\u03BA\u03B5\u03C4\u03B1\u03B9 \u03C3\u03C4\u03BF \u03C0\u03BB\u03B7\u03BA\u03C4\u03C1\u03BF\u03BB\u03CC\u03B3\u03B9\u03BF \u03BA\u03B1\u03B9 \u03B4\u03B5\u03BD \u03C5\u03C0\u03AC\u03C1\u03C7\u03B5\u03B9 \u03B5\u03BC\u03C6\u03B1\u03BD\u03AE\u03C2 \u03C0\u03BB\u03B1\u03CA\u03BD\u03AE \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE, \u03B5\u03AC\u03BD \u03C0\u03B9\u03AD\u03C3\u03B5\u03C4\u03B5 <strong>Shift+Tab</strong>
  \u03B7 \u03B5\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03BC\u03B5\u03C4\u03B1\u03BA\u03B9\u03BD\u03B5\u03AF\u03C4\u03B1\u03B9 \u03C3\u03C4\u03B7\u03BD \u03C0\u03C1\u03CE\u03C4\u03B7 \u03BF\u03BC\u03AC\u03B4\u03B1 \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE\u03C2 \u03B5\u03C1\u03B3\u03B1\u03BB\u03B5\u03AF\u03C9\u03BD, \u03CC\u03C7\u03B9 \u03C3\u03C4\u03B7\u03BD \u03C4\u03B5\u03BB\u03B5\u03C5\u03C4\u03B1\u03AF\u03B1.</p>

<h1>\u03A0\u03BB\u03BF\u03AE\u03B3\u03B7\u03C3\u03B7 \u03B5\u03BD\u03C4\u03CC\u03C2 \u03C4\u03C9\u03BD \u03B5\u03BD\u03BF\u03C4\u03AE\u03C4\u03C9\u03BD \u03C4\u03BF\u03C5 \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7</h1>

<p>\u0393\u03B9\u03B1 \u03BD\u03B1 \u03BC\u03B5\u03C4\u03B1\u03BA\u03B9\u03BD\u03B7\u03B8\u03B5\u03AF\u03C4\u03B5 \u03B1\u03C0\u03CC \u03AD\u03BD\u03B1 \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03BF \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7 \u03C3\u03C4\u03BF \u03B5\u03C0\u03CC\u03BC\u03B5\u03BD\u03BF, \u03C0\u03B9\u03AD\u03C3\u03C4\u03B5 \u03C4\u03BF \u03B1\u03BD\u03C4\u03AF\u03C3\u03C4\u03BF\u03B9\u03C7\u03BF \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03BF <strong>\u03B2\u03AD\u03BB\u03BF\u03C5\u03C2</strong>.</p>

<p>\u039C\u03B5 \u03C4\u03B1 \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03B1 <strong>\u03B1\u03C1\u03B9\u03C3\u03C4\u03B5\u03C1\u03BF\u03CD</strong> \u03BA\u03B1\u03B9 <strong>\u03B4\u03B5\u03BE\u03B9\u03BF\u03CD</strong> \u03B2\u03AD\u03BB\u03BF\u03C5\u03C2</p>

<ul>
  <li>\u03B3\u03AF\u03BD\u03B5\u03C4\u03B1\u03B9 \u03BC\u03B5\u03C4\u03B1\u03BA\u03AF\u03BD\u03B7\u03C3\u03B7 \u03BC\u03B5\u03C4\u03B1\u03BE\u03CD \u03C4\u03C9\u03BD \u03BC\u03B5\u03BD\u03BF\u03CD \u03C3\u03C4\u03B7 \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE \u03BC\u03B5\u03BD\u03BF\u03CD.</li>
  <li>\u03B1\u03BD\u03BF\u03AF\u03B3\u03B5\u03B9 \u03AD\u03BD\u03B1 \u03C5\u03C0\u03BF\u03BC\u03B5\u03BD\u03BF\u03CD \u03C3\u03B5 \u03AD\u03BD\u03B1 \u03BC\u03B5\u03BD\u03BF\u03CD.</li>
  <li>\u03B3\u03AF\u03BD\u03B5\u03C4\u03B1\u03B9 \u03BC\u03B5\u03C4\u03B1\u03BA\u03AF\u03BD\u03B7\u03C3\u03B7 \u03BC\u03B5\u03C4\u03B1\u03BE\u03CD \u03BA\u03BF\u03C5\u03BC\u03C0\u03B9\u03CE\u03BD \u03C3\u03B5 \u03BC\u03B9\u03B1 \u03BF\u03BC\u03AC\u03B4\u03B1 \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE\u03C2 \u03B5\u03C1\u03B3\u03B1\u03BB\u03B5\u03AF\u03C9\u03BD.</li>
  <li>\u03B3\u03AF\u03BD\u03B5\u03C4\u03B1\u03B9 \u03BC\u03B5\u03C4\u03B1\u03BA\u03AF\u03BD\u03B7\u03C3\u03B7 \u03BC\u03B5\u03C4\u03B1\u03BE\u03CD \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03C9\u03BD \u03C3\u03C4\u03B7 \u03B4\u03B9\u03B1\u03B4\u03C1\u03BF\u03BC\u03AE \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03BF\u03C5 \u03C3\u03C4\u03BF \u03C5\u03C0\u03BF\u03C3\u03AD\u03BB\u03B9\u03B4\u03BF.</li>
</ul>

<p>\u039C\u03B5 \u03C4\u03B1 \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03B1 <strong>\u03B5\u03C0\u03AC\u03BD\u03C9</strong> \u03BA\u03B1\u03B9 <strong>\u03BA\u03AC\u03C4\u03C9</strong> \u03B2\u03AD\u03BB\u03BF\u03C5\u03C2</p>

<ul>
  <li>\u03B3\u03AF\u03BD\u03B5\u03C4\u03B1\u03B9 \u03BC\u03B5\u03C4\u03B1\u03BA\u03AF\u03BD\u03B7\u03C3\u03B7 \u03BC\u03B5\u03C4\u03B1\u03BE\u03CD \u03C4\u03C9\u03BD \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03C9\u03BD \u03BC\u03B5\u03BD\u03BF\u03CD \u03C3\u03B5 \u03AD\u03BD\u03B1 \u03BC\u03B5\u03BD\u03BF\u03CD.</li>
  <li>\u03B3\u03AF\u03BD\u03B5\u03C4\u03B1\u03B9 \u03BC\u03B5\u03C4\u03B1\u03BA\u03AF\u03BD\u03B7\u03C3\u03B7 \u03BC\u03B5\u03C4\u03B1\u03BE\u03CD \u03C4\u03C9\u03BD \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03C9\u03BD \u03BC\u03B5\u03BD\u03BF\u03CD \u03C3\u03B5 \u03AD\u03BD\u03B1 \u03B1\u03BD\u03B1\u03B4\u03C5\u03CC\u03BC\u03B5\u03BD\u03BF \u03BC\u03B5\u03BD\u03BF\u03CD \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE\u03C2 \u03B5\u03C1\u03B3\u03B1\u03BB\u03B5\u03AF\u03C9\u03BD.</li>
</ul>

<p>\u039C\u03B5 \u03C4\u03B1 \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03B1 <strong>\u03B2\u03AD\u03BB\u03BF\u03C5\u03C2</strong> \u03B3\u03AF\u03BD\u03B5\u03C4\u03B1\u03B9 \u03BA\u03C5\u03BA\u03BB\u03B9\u03BA\u03AE \u03BC\u03B5\u03C4\u03B1\u03BA\u03AF\u03BD\u03B7\u03C3\u03B7 \u03B5\u03BD\u03C4\u03CC\u03C2 \u03C4\u03B7\u03C2 \u03B5\u03C3\u03C4\u03B9\u03B1\u03C3\u03BC\u03AD\u03BD\u03B7\u03C2 \u03B5\u03BD\u03CC\u03C4\u03B7\u03C4\u03B1\u03C2 \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7.</p>

<p>\u0393\u03B9\u03B1 \u03BD\u03B1 \u03BA\u03BB\u03B5\u03AF\u03C3\u03B5\u03C4\u03B5 \u03AD\u03BD\u03B1 \u03B1\u03BD\u03BF\u03B9\u03C7\u03C4\u03CC \u03BC\u03B5\u03BD\u03BF\u03CD, \u03AD\u03BD\u03B1 \u03B1\u03BD\u03BF\u03B9\u03C7\u03C4\u03CC \u03C5\u03C0\u03BF\u03BC\u03B5\u03BD\u03BF\u03CD \u03AE \u03AD\u03BD\u03B1 \u03B1\u03BD\u03BF\u03B9\u03C7\u03C4\u03CC \u03B1\u03BD\u03B1\u03B4\u03C5\u03CC\u03BC\u03B5\u03BD\u03BF \u03BC\u03B5\u03BD\u03BF\u03CD, \u03C0\u03B9\u03AD\u03C3\u03C4\u03B5 \u03C4\u03BF \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03BF <strong>Esc</strong>.</p>

<p>\u0395\u03AC\u03BD \u03B7 \u03C4\u03C1\u03AD\u03C7\u03BF\u03C5\u03C3\u03B1 \u03B5\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03B2\u03C1\u03AF\u03C3\u03BA\u03B5\u03C4\u03B1\u03B9 \u03C3\u03C4\u03B7\u03BD \u03BA\u03BF\u03C1\u03C5\u03C6\u03AE \u03BC\u03B9\u03B1\u03C2 \u03B5\u03BD\u03CC\u03C4\u03B7\u03C4\u03B1\u03C2 \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD\u03C4\u03BF\u03C2 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B7, \u03C0\u03B9\u03AD\u03B6\u03BF\u03BD\u03C4\u03B1\u03C2 \u03C4\u03BF \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03BF <strong>Esc</strong>,
  \u03B3\u03AF\u03BD\u03B5\u03C4\u03B1\u03B9 \u03B5\u03C0\u03AF\u03C3\u03B7\u03C2 \u03C0\u03BB\u03AE\u03C1\u03B7\u03C2 \u03AD\u03BE\u03BF\u03B4\u03BF\u03C2 \u03B1\u03C0\u03CC \u03C4\u03B7\u03BD \u03C0\u03BB\u03BF\u03AE\u03B3\u03B7\u03C3\u03B7 \u03BC\u03AD\u03C3\u03C9 \u03C0\u03BB\u03B7\u03BA\u03C4\u03C1\u03BF\u03BB\u03BF\u03B3\u03AF\u03BF\u03C5.</p>

<h1>\u0395\u03BA\u03C4\u03AD\u03BB\u03B5\u03C3\u03B7 \u03B5\u03BD\u03CC\u03C2 \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03BF\u03C5 \u03BC\u03B5\u03BD\u03BF\u03CD \u03AE \u03BA\u03BF\u03C5\u03BC\u03C0\u03B9\u03BF\u03CD \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE\u03C2 \u03B5\u03C1\u03B3\u03B1\u03BB\u03B5\u03AF\u03C9\u03BD</h1>

<p>\u038C\u03C4\u03B1\u03BD \u03C4\u03BF \u03B5\u03C0\u03B9\u03B8\u03C5\u03BC\u03B7\u03C4\u03CC \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03BF \u03BC\u03B5\u03BD\u03BF\u03CD \u03AE \u03BA\u03BF\u03C5\u03BC\u03C0\u03AF \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE\u03C2 \u03B5\u03C1\u03B3\u03B1\u03BB\u03B5\u03AF\u03C9\u03BD \u03B5\u03AF\u03BD\u03B1\u03B9 \u03B5\u03C0\u03B9\u03C3\u03B7\u03BC\u03B1\u03C3\u03BC\u03AD\u03BD\u03BF, \u03C0\u03B9\u03AD\u03C3\u03C4\u03B5 \u03C4\u03B1 \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03B1 <strong>Return</strong>, <strong>Enter</strong>,
  \u03AE \u03C4\u03BF <strong>\u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03BF \u03B4\u03B9\u03B1\u03C3\u03C4\u03AE\u03BC\u03B1\u03C4\u03BF\u03C2</strong> \u03B3\u03B9\u03B1 \u03BD\u03B1 \u03B5\u03BA\u03C4\u03B5\u03BB\u03AD\u03C3\u03B5\u03C4\u03B5 \u03C4\u03BF \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03BF.</p>

<h1>\u03A0\u03BB\u03BF\u03AE\u03B3\u03B7\u03C3\u03B7 \u03C3\u03B5 \u03C0\u03B1\u03C1\u03AC\u03B8\u03C5\u03C1\u03B1 \u03B4\u03B9\u03B1\u03BB\u03CC\u03B3\u03BF\u03C5 \u03C7\u03C9\u03C1\u03AF\u03C2 \u03BA\u03B1\u03C1\u03C4\u03AD\u03BB\u03B5\u03C2</h1>

<p>\u03A3\u03B5 \u03C0\u03B1\u03C1\u03AC\u03B8\u03C5\u03C1\u03B1 \u03B4\u03B9\u03B1\u03BB\u03CC\u03B3\u03BF\u03C5 \u03C7\u03C9\u03C1\u03AF\u03C2 \u03BA\u03B1\u03C1\u03C4\u03AD\u03BB\u03B5\u03C2, \u03C4\u03BF \u03C0\u03C1\u03CE\u03C4\u03BF \u03B1\u03BB\u03BB\u03B7\u03BB\u03B5\u03C0\u03B9\u03B4\u03C1\u03B1\u03C3\u03C4\u03B9\u03BA\u03CC \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03BF \u03BB\u03B1\u03BC\u03B2\u03AC\u03BD\u03B5\u03B9 \u03C4\u03B7\u03BD \u03B5\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03CC\u03C4\u03B1\u03BD \u03B1\u03BD\u03BF\u03AF\u03B3\u03B5\u03B9 \u03C4\u03BF \u03C0\u03B1\u03C1\u03AC\u03B8\u03C5\u03C1\u03BF \u03B4\u03B9\u03B1\u03BB\u03CC\u03B3\u03BF\u03C5.</p>

<p>\u039C\u03C0\u03BF\u03C1\u03B5\u03AF\u03C4\u03B5 \u03BD\u03B1 \u03C0\u03BB\u03BF\u03B7\u03B3\u03B7\u03B8\u03B5\u03AF\u03C4\u03B5 \u03BC\u03B5\u03C4\u03B1\u03BE\u03CD \u03C4\u03C9\u03BD \u03B1\u03BB\u03BB\u03B7\u03BB\u03B5\u03C0\u03B9\u03B4\u03C1\u03B1\u03C3\u03C4\u03B9\u03BA\u03CE\u03BD \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03C9\u03BD \u03C0\u03B1\u03C1\u03B1\u03B8\u03CD\u03C1\u03C9\u03BD \u03B4\u03B9\u03B1\u03BB\u03CC\u03B3\u03C9\u03BD \u03C0\u03B9\u03AD\u03B6\u03BF\u03BD\u03C4\u03B1\u03C2 \u03C4\u03B1 \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03B1 <strong>Tab</strong> \u03AE <strong>Shift+Tab</strong>.</p>

<h1>\u03A0\u03BB\u03BF\u03AE\u03B3\u03B7\u03C3\u03B7 \u03C3\u03B5 \u03C0\u03B1\u03C1\u03AC\u03B8\u03C5\u03C1\u03B1 \u03B4\u03B9\u03B1\u03BB\u03CC\u03B3\u03BF\u03C5 \u03BC\u03B5 \u03BA\u03B1\u03C1\u03C4\u03AD\u03BB\u03B5\u03C2</h1>

<p>\u03A3\u03B5 \u03C0\u03B1\u03C1\u03AC\u03B8\u03C5\u03C1\u03B1 \u03B4\u03B9\u03B1\u03BB\u03CC\u03B3\u03BF\u03C5 \u03BC\u03B5 \u03BA\u03B1\u03C1\u03C4\u03AD\u03BB\u03B5\u03C2, \u03C4\u03BF \u03C0\u03C1\u03CE\u03C4\u03BF \u03BA\u03BF\u03C5\u03BC\u03C0\u03AF \u03C3\u03C4\u03BF \u03BC\u03B5\u03BD\u03BF\u03CD \u03BA\u03B1\u03C1\u03C4\u03AD\u03BB\u03B1\u03C2 \u03BB\u03B1\u03BC\u03B2\u03AC\u03BD\u03B5\u03B9 \u03C4\u03B7\u03BD \u03B5\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03CC\u03C4\u03B1\u03BD \u03B1\u03BD\u03BF\u03AF\u03B3\u03B5\u03B9 \u03C4\u03BF \u03C0\u03B1\u03C1\u03AC\u03B8\u03C5\u03C1\u03BF \u03B4\u03B9\u03B1\u03BB\u03CC\u03B3\u03BF\u03C5.</p>

<p>\u039C\u03C0\u03BF\u03C1\u03B5\u03AF\u03C4\u03B5 \u03BD\u03B1 \u03C0\u03BB\u03BF\u03B7\u03B3\u03B7\u03B8\u03B5\u03AF\u03C4\u03B5 \u03BC\u03B5\u03C4\u03B1\u03BE\u03CD \u03C4\u03C9\u03BD \u03B1\u03BB\u03BB\u03B7\u03BB\u03B5\u03C0\u03B9\u03B4\u03C1\u03B1\u03C3\u03C4\u03B9\u03BA\u03CE\u03BD \u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03AF\u03C9\u03BD \u03B1\u03C5\u03C4\u03AE\u03C2 \u03C4\u03B7\u03C2 \u03BA\u03B1\u03C1\u03C4\u03AD\u03BB\u03B1 \u03B4\u03B9\u03B1\u03BB\u03CC\u03B3\u03BF\u03C5 \u03C0\u03B9\u03AD\u03B6\u03BF\u03BD\u03C4\u03B1\u03C2 \u03C4\u03B1 \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03B1 <strong>Tab</strong> \u03AE
  <strong>Shift+Tab</strong>.</p>

<p>\u039C\u03C0\u03BF\u03C1\u03B5\u03AF\u03C4\u03B5 \u03BD\u03B1 \u03BA\u03AC\u03BD\u03B5\u03C4\u03B5 \u03B5\u03BD\u03B1\u03BB\u03BB\u03B1\u03B3\u03AE \u03C3\u03B5 \u03AC\u03BB\u03BB\u03B7 \u03BA\u03B1\u03C1\u03C4\u03AD\u03BB\u03B1 \u03C4\u03BF\u03C5 \u03C0\u03B1\u03C1\u03B1\u03B8\u03CD\u03C1\u03BF\u03C5 \u03B4\u03B9\u03B1\u03BB\u03CC\u03B3\u03BF\u03C5, \u03BC\u03B5\u03C4\u03B1\u03C6\u03AD\u03C1\u03BF\u03BD\u03C4\u03B1\u03C2 \u03C4\u03B7\u03BD \u03B5\u03C3\u03C4\u03AF\u03B1\u03C3\u03B7 \u03C3\u03C4\u03BF \u03BC\u03B5\u03BD\u03BF\u03CD \u03BA\u03B1\u03C1\u03C4\u03AD\u03BB\u03B1\u03C2 \u03BA\u03B1\u03B9 \u03C0\u03B9\u03AD\u03B6\u03BF\u03BD\u03C4\u03B1\u03C2 \u03C4\u03BF \u03BA\u03B1\u03C4\u03AC\u03BB\u03BB\u03B7\u03BB\u03BF \u03C0\u03BB\u03AE\u03BA\u03C4\u03C1\u03BF <strong>\u03B2\u03AD\u03BB\u03BF\u03C5\u03C2</strong>
  \u03B3\u03B9\u03B1 \u03BD\u03B1 \u03BC\u03B5\u03C4\u03B1\u03BA\u03B9\u03BD\u03B7\u03B8\u03B5\u03AF\u03C4\u03B5 \u03BA\u03C5\u03BA\u03BB\u03B9\u03BA\u03AC \u03C3\u03C4\u03B9\u03C2 \u03B4\u03B9\u03B1\u03B8\u03AD\u03C3\u03B9\u03BC\u03B5\u03C2 \u03BA\u03B1\u03C1\u03C4\u03AD\u03BB\u03B5\u03C2.</p>
`);
